import pytest
import requests

@pytest.mark.parametrize("bad_password,reason", [
    ("short", "too_short"),
    ("alllowercasenumbers123", "no_special_or_upper"),
    ("NoDigitsOrSpecial!", "no_digit"),
])
def test_reset_password_policy_violation_returns_422(
    valid_reset_token_factory, webhook_capture_fixture, api_base_url,
    bad_password, reason
):
    token = valid_reset_token_factory()
    payload = {"token": token, "password": bad_password}
    resp = requests.post(f"{api_base_url}/password/reset", json=payload)
    assert resp.status_code == 422, (
        f"[{reason}] Expected 422, got {resp.status_code}"
    )
    body = resp.json()
    assert "password" in str(body).lower(), (
        f"[{reason}] Expected password field error in body: {body}"
    )
    events = webhook_capture_fixture.get_events(event_type="password.reset")
    assert len(events) == 0, f"[{reason}] Unexpected webhook events: {events}"
